import os
import json
import threading
from collections import Counter, defaultdict
from datetime import datetime
from flask import Flask, request, jsonify
import numpy as np
from PIL import Image
import io
import base64

app = Flask(__name__)

class DataLabelingSystem:
    def __init__(self):
        self.images = {}
        self.annotations = defaultdict(list)
        self.aggregated_labels = {}
        self.lock = threading.Lock()
        self.model = None
        self.training_data = []
        
    def add_image(self, image_id, image_data, metadata=None):
        with self.lock:
            self.images[image_id] = {
                'data': image_data,
                'metadata': metadata or {},
                'created_at': datetime.now().isoformat()
            }
            
    def add_annotation(self, image_id, annotator_id, label, confidence=1.0):
        with self.lock:
            if image_id not in self.images:
                return False
            
            annotation = {
                'annotator_id': annotator_id,
                'label': label,
                'confidence': confidence,
                'timestamp': datetime.now().isoformat()
            }
            self.annotations[image_id].append(annotation)
            return True
    
    def aggregate_labels(self, min_annotations=3):
        with self.lock:
            for image_id, annotations in self.annotations.items():
                if len(annotations) >= min_annotations:
                    labels = [ann['label'] for ann in annotations]
                    label_counts = Counter(labels)
                    majority_label = label_counts.most_common(1)[0][0]
                    majority_count = label_counts[majority_label]
                    
                    self.aggregated_labels[image_id] = {
                        'label': majority_label,
                        'confidence': majority_count / len(annotations),
                        'total_annotations': len(annotations),
                        'label_distribution': dict(label_counts)
                    }
                    
    def get_training_data(self):
        self.aggregate_labels()
        training_data = []
        
        with self.lock:
            for image_id, label_info in self.aggregated_labels.items():
                if image_id in self.images:
                    training_data.append({
                        'image_id': image_id,
                        'image_data': self.images[image_id]['data'],
                        'label': label_info['label'],
                        'confidence': label_info['confidence']
                    })
        
        return training_data
    
    def train_model(self, model_type='simple'):
        training_data = self.get_training_data()
        
        if not training_data:
            return False
        
        X = []
        y = []
        
        for item in training_data:
            image_data = item['image_data']
            
            if isinstance(image_data, str):
                try:
                    image_bytes = base64.b64decode(image_data)
                    img = Image.open(io.BytesIO(image_bytes))
                except:
                    continue
            else:
                img = Image.open(io.BytesIO(image_data))
            
            img = img.convert('RGB')
            img = img.resize((32, 32))
            img_array = np.array(img).flatten()
            
            X.append(img_array)
            y.append(item['label'])
        
        if not X:
            return False
        
        X = np.array(X)
        y = np.array(y)
        
        unique_labels = np.unique(y)
        label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
        y_encoded = np.array([label_to_idx[label] for label in y])
        
        self.model = SimpleClassifier(X.shape[1], len(unique_labels))
        self.model.train(X, y_encoded, epochs=10)
        self.model.label_mapping = label_to_idx
        self.model.idx_to_label = {idx: label for label, idx in label_to_idx.items()}
        
        return True
    
    def predict(self, image_data):
        if self.model is None:
            return None
        
        if isinstance(image_data, str):
            try:
                image_bytes = base64.b64decode(image_data)
                img = Image.open(io.BytesIO(image_bytes))
            except:
                return None
        else:
            img = Image.open(io.BytesIO(image_data))
        
        img = img.convert('RGB')
        img = img.resize((32, 32))
        img_array = np.array(img).flatten()
        
        prediction_idx = self.model.predict(img_array.reshape(1, -1))[0]
        prediction_label = self.model.idx_to_label[prediction_idx]
        
        return prediction_label
    
    def get_statistics(self):
        with self.lock:
            stats = {
                'total_images': len(self.images),
                'total_annotations': sum(len(anns) for anns in self.annotations.values()),
                'images_with_annotations': len(self.annotations),
                'aggregated_labels': len(self.aggregated_labels),
                'model_trained': self.model is not None
            }
            return stats


class SimpleClassifier:
    def __init__(self, input_size, num_classes):
        self.input_size = input_size
        self.num_classes = num_classes
        self.weights = np.random.randn(input_size, num_classes) * 0.01
        self.bias = np.zeros(num_classes)
        
    def softmax(self, x):
        exp_x = np.exp(x - np.max(x, axis=1, keepdims=True))
        return exp_x / np.sum(exp_x, axis=1, keepdims=True)
    
    def train(self, X, y, epochs=10, learning_rate=0.01):
        n_samples = X.shape[0]
        
        for epoch in range(epochs):
            logits = np.dot(X, self.weights) + self.bias
            probs = self.softmax(logits)
            
            y_one_hot = np.zeros((n_samples, self.num_classes))
            y_one_hot[np.arange(n_samples), y] = 1
            
            dlogits = probs - y_one_hot
            dweights = np.dot(X.T, dlogits) / n_samples
            dbias = np.sum(dlogits, axis=0) / n_samples
            
            self.weights -= learning_rate * dweights
            self.bias -= learning_rate * dbias
    
    def predict(self, X):
        logits = np.dot(X, self.weights) + self.bias
        return np.argmax(logits, axis=1)


labeling_system = DataLabelingSystem()


@app.route('/api/images', methods=['POST'])
def add_image():
    data = request.get_json()
    
    if not data or 'image_id' not in data or 'image_data' not in data:
        return jsonify({'error': 'Missing required fields'}), 400
    
    image_id = data['image_id']
    image_data = data['image_data']
    metadata = data.get('metadata', {})
    
    labeling_system.add_image(image_id, image_data, metadata)
    
    return jsonify({
        'status': 'success',
        'image_id': image_id,
        'message': 'Image added successfully'
    }), 201


@app.route('/api/annotations', methods=['POST'])
def add_annotation():
    data = request.get_json()
    
    required_fields = ['image_id', 'annotator_id', 'label']
    if not data or not all(field in data for field in required_fields):
        return jsonify({'error': 'Missing required fields'}), 400
    
    image_id = data['image_id']
    annotator_id = data['annotator_id']
    label = data['label']
    confidence = data.get('confidence', 1.0)
    
    success = labeling_system.add_annotation(image_id, annotator_id, label, confidence)
    
    if not success:
        return jsonify({'error': 'Image not found'}), 404
    
    return jsonify({
        'status': 'success',
        'message': 'Annotation added successfully'
    }), 201


